import os,struct,itertools
f0='/home/ctfplayer/ctf_files/disk.img0'
f1='/home/ctfplayer/ctf_files/disk.img1'
size=os.path.getsize(f0)
chunks=[512,4096,8192,16384,32768,65536,131072,262144,524288,1048576]
# read first 8 MiB from each
MAX=8*1024*1024
with open(f0,'rb') as a, open(f1,'rb') as b:
    d0=a.read(MAX)
    d1=b.read(MAX)

def xor_bytes(a,b):
    return bytes(x^y for x,y in zip(a,b))

# candidate parity rotation functions over stripe s for 3 disks
pfuncs={
    'left_sym': lambda s: (2 - (s%3)),
    'right_sym': lambda s: (s%3),
}
# data order formulas given parity position p and stripe s
# return ordered list of disk positions for data in logical order
# checkerboard: alternate ascending/descending of non-parity positions

def nonpar(p):
    return [i for i in range(3) if i!=p]

orders={
    'asc': lambda p,s: nonpar(p),
    'desc': lambda p,s: list(reversed(nonpar(p))),
    'checker': lambda p,s: nonpar(p) if s%2==0 else list(reversed(nonpar(p))),
    'inv_checker': lambda p,s: list(reversed(nonpar(p))) if s%2==0 else nonpar(p),
}

sigs=[(0,b'EFI PART'),(3,b'NTFS    ')]
for cs in chunks:
    stripes=MAX//cs
    for pname,pf in pfuncs.items():
        for oname,of in orders.items():
            out=bytearray()
            for s in range(stripes):
                p=pf(s)
                order=of(p,s)
                # map disk pos to chunk bytes; pos0=disk0,pos1=disk1,pos2=missing
                c0=d0[s*cs:(s+1)*cs]
                c1=d1[s*cs:(s+1)*cs]
                # determine chunks for ordered data positions
                # if missing is parity => emit disk0/disk1 if they are data in proper order
                # if missing is data => recover missing = xor(parity,data)
                posbytes={0:c0,1:c1}
                if p==2:
                    # missing parity, both observed are data
                    for pos in order:
                        out += posbytes[pos]
                else:
                    miss = [x for x in [0,1,2] if x not in posbytes][0]
                    # miss always 2 actually
                    rec = xor_bytes(posbytes[p], posbytes[[x for x in [0,1] if x!=p][0]])
                    for pos in order:
                        out += rec if pos==2 else posbytes[pos]
            # test signatures at expected places
            score=[]
            for off,sig in sigs:
                idx=out.find(sig,0,2*1024*1024)
                if idx!=-1: score.append((sig,idx))
            if score:
                print('cs',cs,pname,oname,score[:5], 'start',out[:16].hex())
