import os, struct, itertools

files=[open('/home/ctfplayer/ctf_files/disk.img0','rb'), open('/home/ctfplayer/ctf_files/disk.img1','rb')]
size=os.path.getsize('/home/ctfplayer/ctf_files/disk.img0')
chunks=[512,4096,8192,16384,32768,65536,131072,262144,524288,1048576]

# two data layouts for 3-disk RAID5 with checkerboard (symmetric) and parity inverted layouts
# parity disk per stripe can be left or right asymmetric/inverted
# for each stripe, fill surviving disks 0 and 1 from files, missing disk 2 is zeros unless computed parity needed? virtual output concatenates data blocks only.
# We only need map logical data chunks to physical chunks on each disk.

def layout(stripe, parity_mode, data_mode):
    # returns parity disk and ordered list of data disks as they appear in logical order for that stripe
    # parity_mode: 'left' => 2,1,0 repeating; 'right' => 0,1,2 repeating
    if parity_mode=='left':
        p=(2 - (stripe % 3))
    elif parity_mode=='right':
        p=(stripe % 3)
    else:
        raise
    data=[d for d in range(3) if d!=p]
    # checkerboard / symmetric means data order alternates each stripe
    if data_mode=='fwd':
        if stripe % 2 == 1:
            data=list(reversed(data))
    elif data_mode=='rev':
        if stripe % 2 == 0:
            data=list(reversed(data))
    else:
        raise
    return p,data


def read_chunk(disk, chunk_index, csize):
    if disk==2:
        return b'\x00'*csize
    f=files[disk]
    off=chunk_index*csize
    f.seek(off)
    return f.read(csize)


def reconstruct_prefix(csize, parity_mode, data_mode, outbytes=8*1024*1024):
    out=[]
    needed_chunks=(outbytes + csize -1)//csize
    logical=0
    stripe=0
    while logical<needed_chunks:
        p,data=layout(stripe, parity_mode, data_mode)
        for d in data:
            out.append(read_chunk(d, stripe, csize))
            logical += 1
            if logical>=needed_chunks:
                break
        stripe += 1
    return b''.join(out)[:outbytes]


def score(buf):
    hits=[]
    # MBR sig at 510
    if len(buf)>=512 and buf[510:512]==b'\x55\xaa':
        hits.append('MBR55AA')
    if b'EFI PART' in buf[:65536]:
        hits.append('GPT')
    if len(buf)>=512 and buf[3:11] in (b'NTFS    ', b'EXFAT   '):
        hits.append('BOOT:'+buf[3:11].decode('ascii','ignore'))
    # ext superblock at 1024+56
    if len(buf)>=2048 and buf[1024+56:1024+58]==b'\x53\xef':
        hits.append('EXTSB')
    for sig in [b'PK\x03\x04', b'\x89PNG\r\n\x1a\n', b'Rar!\x1a\x07', b'7z\xbc\xaf\x27\x1c']:
        idx=buf.find(sig)
        if 0 <= idx < 65536:
            hits.append(f'{sig!r}@{idx:x}')
    return hits

for c in chunks:
    for pm in ['left','right']:
        for dm in ['fwd','rev']:
            buf=reconstruct_prefix(c, pm, dm)
            hits=score(buf)
            if hits:
                print(c, pm, dm, hits)

