files=[open('/home/ctfplayer/ctf_files/disk.img0','rb'), open('/home/ctfplayer/ctf_files/disk.img1','rb')]
chunks=[512,4096,8192,16384,32768,65536,131072,262144,524288,1048576]
virt_size=3*786432016  # rough upper bound not exact useful only compare LBAs

# assume missing disk index 2

def layout(stripe, parity_mode, data_mode):
    p=(2 - (stripe % 3)) if parity_mode=='left' else (stripe % 3)
    data=[d for d in range(3) if d!=p]
    if data_mode=='fwd':
        if stripe % 2 == 1:
            data=list(reversed(data))
    else:
        if stripe % 2 == 0:
            data=list(reversed(data))
    return p,data

def read_chunk(disk, stripe, csize):
    if disk==2:
        return b'\x00'*csize
    f=files[disk]; f.seek(stripe*csize); return f.read(csize)

def read_logical(offset, length, csize, parity_mode, data_mode):
    out=b''
    while length>0:
        chunkno=offset//csize
        inoff=offset%csize
        stripe=chunkno//2
        pos=chunkno%2
        _,data=layout(stripe, parity_mode, data_mode)
        disk=data[pos]
        chunk=read_chunk(disk, stripe, csize)
        take=min(length, csize-inoff)
        out += chunk[inoff:inoff+take]
        offset += take; length -= take
    return out

def guid_nonzero(b): return any(x!=0 for x in b)

for c in chunks:
  for pm in ['left','right']:
    for dm in ['fwd','rev']:
      mbr=read_logical(0,512,c,pm,dm)
      hdr=read_logical(512,512,c,pm,dm)
      score=[]
      if mbr[510:512]==b'\x55\xaa': score.append('mbrsig')
      if hdr[:8]==b'EFI PART':
        rev,hsize,hcrc=struct.unpack('<III',hdr[8:20])
        cur,backup,first,last=struct.unpack('<QQQQ',hdr[24:56])
        entries_lba,num_entries,entry_size,arr_crc=struct.unpack('<QIII',hdr[72:92])
        if hsize>=92 and hsize<=512: score.append('gpthdr')
        if cur==1: score.append('curlba1')
        if entries_lba>=2 and num_entries>0 and entry_size in (128,256): score.append(f'entries:{entries_lba}/{num_entries}/{entry_size}')
        ent=read_logical(entries_lba*512, min(4096,num_entries*entry_size), c, pm, dm)
        nz=0
        first_lbas=[]
        for i in range(0,len(ent),entry_size):
            e=ent[i:i+entry_size]
            if len(e)<entry_size: break
            if guid_nonzero(e[:16]):
                nz += 1
                first_lba,last_lba=struct.unpack('<QQ',e[32:48])
                first_lbas.append((first_lba,last_lba))
        score.append(f'nzparts:{nz}')
        if nz and all(a<=b for a,b in first_lbas): score.append('partlbasane')
      if len(score)>=5:
        print(c,pm,dm,score)

