def layout(stripe, parity_left, checker_even_forward):
    # parity inverted layout: left-symmetric = 2-(stripe%3)
    p=(2-(stripe%3)) if parity_left else (stripe%3)
    data=[d for d in range(3) if d!=p]
    # checkerboard data alternation: swap order every stripe
    rev = (stripe % 2 == 1) if checker_even_forward else (stripe % 2 == 0)
    if rev: data=list(reversed(data))
    return p,data

def read_chunk(disk, stripe, csize):
    if disk==2: return b'\x00'*csize
    f=files[disk]; f.seek(stripe*csize); return f.read(csize)

