    out=bytearray()
    while n>0:
        chunkno=off//csize; inoff=off%csize
        stripe=chunkno//2; pos=chunkno%2
        _,data=layout(stripe, parity_left, checker_even_forward)
        chunk=read_chunk(data[pos], stripe, csize)
        take=min(n, csize-inoff)
        out += chunk[inoff:inoff+take]
        off += take; n -= take
    return bytes(out)

