chunks=[512,4096,8192,16384,32768,65536,131072,262144,524288,1048576]

# parity_mode: 'left' => p=2-(s%3), 'right' => p=s%3
# data_mode checkerboard on stripe parity: even/odd stripes reversed or not

def layout(s, parity_left, reverse_on_odd):
    p=(2-(s%3)) if parity_left else (s%3)
    data=[d for d in range(3) if d!=p]
    if reverse_on_odd:
        if s%2==1: data.reverse()
    else:
        if s%2==0: data.reverse()
    return p,data

def read_disk(disk, stripe, c):
    if disk==2:
        return b'\x00'*c
    f=fs[disk]
    f.seek(stripe*c)
    b=f.read(c)
    if len(b)<c: b += b'\x00'*(c-len(b))
    return b

def logical_chunk(chunkno,c,parity_left,reverse_on_odd):
    stripe=chunkno//2
    pos=chunkno%2
    p,data=layout(stripe,parity_left,reverse_on_odd)
    return read_disk(data[pos],stripe,c)

def logical_read(off,n,c,parity_left,reverse_on_odd):
    out=bytearray()
    while n:
        chunkno=off//c; inner=off%c
        blk=logical_chunk(chunkno,c,parity_left,reverse_on_odd)
        take=min(n,c-inner)
        out += blk[inner:inner+take]
        off += take; n -= take
    return bytes(out)

def score(buf):
    hits=[]
    if len(buf)>=512 and buf[510:512]==b'\x55\xaa': hits.append('MBR55AA@0')
    if b'EFI PART' in buf[:4096]: hits.append('GPTHDR')
    if len(buf)>=4096+0x438 and buf[4096+0x438:4096+0x43a]==b'S\xef': hits.append('EXTSB@4096+1080')
    # NTFS at 0 or partition starts maybe later; just scan first 4MiB each 512b boundary for jump+NTFS
    for off in range(0,min(len(buf)-11,4*1024*1024),512):
        if buf[off+3:off+11]==b'NTFS    ': hits.append(f'NTFS@{off}'); break
    for sig,name in [(b'PK\x03\x04','ZIP'),(b'\x89PNG\r\n\x1a\n','PNG'),(b'Rar!\x1a\x07\x00','RAR'),(b'\x7fELF','ELF')]:
        idx=buf.find(sig)
        if 0 <= idx < 2*1024*1024: hits.append(f'{name}@{idx}')
    return hits

for c in chunks:
    for parity_left in [False,True]:
        for reverse_on_odd in [False,True]:
            buf=logical_read(0,4*1024*1024,c,parity_left,reverse_on_odd)
