import struct, os
paths=['/home/ctfplayer/ctf_files/disk.img0','/home/ctfplayer/ctf_files/disk.img1']
fs=[open(p,'rb') for p in paths]

def layout(s, parity_left, reverse_on_odd):
    p=(2-(s%3)) if parity_left else (s%3)
    data=[d for d in range(3) if d!=p]
    if reverse_on_odd:
        if s%2==1: data.reverse()
    else:
        if s%2==0: data.reverse()
    return p,data

def read_disk(disk, stripe, c):
    if disk==2:return b'\x00'*c
    f=fs[disk]; f.seek(stripe*c); b=f.read(c)
    return b+b'\x00'*(c-len(b))

def read(off,n,c,pl,ro):
    out=bytearray()
