# layouts over stripe number s
# returns parity disk pd and ordered data disks for logical blocks within stripe
# checkerboard means data order alternates with parity row; parity inverted means parity rotates high->low

def layout_left_asymmetric(s):
    pd=(N-1 - (s%N))
    data=[d for d in range(N) if d!=pd]
    return pd,data

def layout_right_asymmetric(s):
    pd=(s%N)
    data=[d for d in range(N) if d!=pd]
    return pd,data

def layout_left_symmetric(s):
    pd=(N-1 - (s%N))
    data=[]
    for i in range(1,N):
        data.append((pd+i)%N)
    return pd,data

def layout_right_symmetric(s):
    pd=(s%N)
    data=[]
    for i in range(1,N):
        data.append((pd+i)%N)
    return pd,data

# variants with reverse data order each stripe (checkerboard-ish)
def alt_data(base):
    def f(s):
        pd,data=base(s)
        if s%2: data=list(reversed(data))
        return pd,data
    return f

