    f=present.get(disk)
    if f is None:
        return b'\x00'*sz
    f.seek(off)
    return f.read(sz)

def reconstruct(layout, chunk, out_bytes):
    out=bytearray()
    stripe_data=(N-1)*chunk
    for lba in range(0, out_bytes, stripe_data):
        s=lba//stripe_data
        pd, data_disks = layout(s)
        # each logical chunk in stripe maps to one of data disks in order
        for disk in data_disks:
            out += disk_read(disk, s*chunk, chunk)
            if len(out)>=out_bytes:
                return bytes(out[:out_bytes])
    return bytes(out[:out_bytes])

