                break
            if sec[54:62]==b'FAT32   ' and sec[510:512]==b'\x55\xaa':
                score+=12; hits.append(f'FAT32@{off}')
                break
        # ext superblock at partition+1024; search first MiB every 512
        for off in range(0,1024*1024):
