#!/usr/bin/env python3
import os, re
from itertools import product
paths=['/home/ctfplayer/ctf_files/disk.img0','/home/ctfplayer/ctf_files/disk.img1']
files=[open(p,'rb') for p in paths]
sizes=[os.path.getsize(p) for p in paths]
chunks=[512,4096,8192,16384,32768,65536,131072,262144,524288,1048576]
header_opts=[0,16]
positions=[(0,1),(1,0),(0,2),(2,0),(1,2),(2,1)] # locations of img0,img1 among 3 disks

def parity_disk(stripe,mode):
    return 2-(stripe%3) if mode=='inv_right' else stripe%3

def data_order(stripe,p,mode):
    rem=[d for d in range(3) if d!=p]
    asc=rem; desc=rem[::-1]
    if mode=='alt0': return asc if stripe%2==0 else desc
    if mode=='alt1': return desc if stripe%2==0 else asc
    if mode=='fixed_asc': return asc
    if mode=='fixed_desc': return desc

def read_member(member_map,disk,chunk,cs,hoff):
    if disk not in member_map: return None
    fi=member_map[disk]
    off=hoff+chunk*cs
    if off+cs>sizes[fi]: return None
    files[fi].seek(off)
    return files[fi].read(cs)

for hoff,cs,pmode,dmode,pos in product(header_opts,chunks,['inv_right','inv_left'],['alt0','alt1','fixed_asc','fixed_desc'],positions):
    member_map={pos[0]:0,pos[1]:1}
    need=8*1024*1024
    out=bytearray()
    stripes=(need + 2*cs -1)//(2*cs)
    for s in range(stripes):
        p=parity_disk(s,pmode)
        order=data_order(s,p,dmode)
        for di in range(2):
            ch=read_member(member_map,order[di],s,cs,hoff)
            if ch is None: break
            out.extend(ch)
    # search signatures anywhere in first few MiB
    findings=[]
    for m in re.finditer(b'EFI PART', out): findings.append(('GPT',m.start()))
    for m in re.finditer(b'NTFS    ', out): findings.append(('NTFS',m.start()-3))
    # MBR at sector boundary with 55aa
    for off in range(0, min(len(out)-512, 2*1024*1024), 512):
        if out[off+510:off+512]==b'\x55\xaa':
            pt=out[off+446:off+510]
            # plausible if partition type not all zero
            if any(pt): findings.append(('MBR',off))
    if findings:
        print('CAND',{'hoff':hoff,'cs':cs,'pmode':pmode,'dmode':dmode,'pos':pos},findings[:10])

#!/usr/bin/env python3
import os, itertools, struct
paths=['/home/ctfplayer/ctf_files/disk.img0','/home/ctfplayer/ctf_files/disk.img1']
files=[open(p,'rb') for p in paths]
chunks=[512,4096,8192,16384,32768,65536,131072,262144,524288,1048576]
headers=[0,16,4096,8192,65536,1048576]
member_positions=[(0,1),(0,2),(1,0),(1,2),(2,0),(2,1)]

def parity(stripe,mode):
    if mode=='inv_right': return 2-(stripe%3)
    if mode=='right': return stripe%3

def order(stripe,p,mode):
    rem=[d for d in range(3) if d!=p]
    asc=rem; desc=rem[::-1]
    if mode=='checker': return asc if stripe%2==0 else desc
    if mode=='checker_rev': return desc if stripe%2==0 else asc

def build(mm,cs,hoff,pmode,dmode,need=6*1024*1024):
    out=bytearray(); stripes=(need + 2*cs -1)//(2*cs)
    for s in range(stripes):
        p=parity(s,pmode); od=order(s,p,dmode)
        for d in od:
            if d in mm:
                fi=mm[d]
                off=hoff+s*cs
                files[fi].seek(off)
                out.extend(files[fi].read(cs))
            else:
                out.extend(b'\x00'*cs)
            if len(out)>=need: return bytes(out[:need])
    return bytes(out[:need])

def score(buf):
    sc=0; reasons=[]
    if buf[510:512]==b'\x55\xaa': sc+=5; reasons.append('MBR55AA')
    if buf[512:520]==b'EFI PART': sc+=20; reasons.append('GPT@1')
    if b'NTFS' in buf[3:11]: sc+=15; reasons.append('NTFSboot@0')
    # look for NTFS boot sector at common partition offsets
    for off in [1048576, 2097152, 4194304, 65536, 32768, 16384, 8192, 512]:
        if off+11 <= len(buf):
            if buf[off:off+3] in [b'\xebR\x90', b'\xeb\x52\x90', b'\xeb\x58\x90', b'\xe9\x00\x00'] and b'NTFS' in buf[off+3:off+11]:
                sc+=30; reasons.append(f'NTFS@{off}')
            if buf[off+1080:off+1082]==b'\x53\xef':
                sc+=25; reasons.append(f'EXT@{off}')
    if b'flag{' in buf: sc+=100; reasons.append('flag')
    return sc,reasons

best=[]
for hoff in headers:
  for cs in chunks:
    for pm in ['inv_right','right']:
      for dm in ['checker','checker_rev']:
        for pos in member_positions:
          mm={pos[0]:0,pos[1]:1}
          buf=build(mm,cs,hoff,pm,dm)
          sc,rs=score(buf)
          if sc:
            best.append((sc,hoff,cs,pm,dm,pos,rs,buf[510:520],buf[1048576+3:1048576+11]))
best.sort(reverse=True)
for x in best[:30]:
    print(x[:-2], 'mbr/gpt=',x[-2], 'oem1m=', x[-1])

