# disk roles per stripe for 3-disk RAID5 with one missing member.
# parity in inverted layout = parity rotates right: 2,1,0,2,1,0...
# checkerboard data = remaining two disks used in alternating order each stripe.
# We model two variants for data order among remaining disks.

def rolemap(stripe, variant):
    p = (2 - (stripe % 3)) % 3  # parity disk index
    rem=[d for d in range(3) if d!=p]
    if variant==0:
        # ascending order
        d0,d1=sorted(rem)
    else:
        # descending order
        d0,d1=sorted(rem, reverse=True)
    return [d0,d1,p]


def reconstruct_prefix(chunk, variant, outsz=4*1024*1024):
    total_stripes=(outsz + (2*chunk)-1)//(2*chunk)
    with open(img0,'rb') as f0, open(img1,'rb') as f1:
        out=bytearray()
        for s in range(total_stripes):
            roles=rolemap(s,variant)
            off=s*chunk
            blocks={0:None,1:None,2:None}
            if off<size0:
                f0.seek(off); blocks[0]=f0.read(chunk)
                f1.seek(off); blocks[1]=f1.read(chunk)
            # disk2 missing
            for pos in [0,1]:
                d=roles[pos]
                blk=blocks.get(d)
                if blk is None:
                    blk=b'\x00'*chunk
                out += blk
                if len(out)>=outsz:
                    return bytes(out[:outsz])
        return bytes(out[:outsz])


def score(buf):
    s=[]
    if len(buf)>=512 and buf[510:512]==b'\x55\xaa':
        s.append('MBR55AA@0')
    if b'EFI PART' in buf[:4096]:
        s.append('GPTHDR')
