            s.append(f'EXTSB@{off:#x}')
    # detect printable volume boot text
    if b'Invalid partition table' in buf[:4096]:
        s.append('MBRtext')
    return s

for chunk in chunks:
    for variant in [0,1]:
        buf=reconstruct_prefix(chunk,variant)
        sig=score(buf)
